package com.parkflow.mall.reservation;
import com.fasterxml.jackson.databind.JsonNode;import com.fasterxml.jackson.databind.ObjectMapper;import io.jsonwebtoken.Jwts;import io.jsonwebtoken.security.Keys;import java.nio.charset.StandardCharsets;import java.time.Instant;import java.util.Date;import java.util.List;import java.util.UUID;import org.junit.jupiter.api.Test;import org.springframework.beans.factory.annotation.Autowired;import org.springframework.boot.test.autoconfigure.web.servlet.AutoConfigureMockMvc;import org.springframework.boot.test.context.SpringBootTest;import org.springframework.http.MediaType;import org.springframework.test.web.servlet.MockMvc;import static org.springframework.test.web.servlet.request.MockMvcRequestBuilders.*;import static org.springframework.test.web.servlet.result.MockMvcResultMatchers.*;
@SpringBootTest(properties={"app.motorbike-capacity=20","app.car-capacity=1"}) @AutoConfigureMockMvc class ReservationWorkflowTests { static final String SECRET="parkflow-local-development-secret-change-me-2026"; @Autowired MockMvc mvc; @Autowired ObjectMapper json;
 @Test void createLookupCancelAndOneActivePlateRulesWork() throws Exception {String plate=plate();String code=create(plate,"MOTORBIKE");mvc.perform(get("/api/reservations/{code}",code)).andExpect(status().isOk()).andExpect(jsonPath("$.status").value("RESERVED"));mvc.perform(post("/api/reservations").contentType(MediaType.APPLICATION_JSON).content(body(plate,"MOTORBIKE",20,80))).andExpect(status().isConflict());mvc.perform(post("/api/reservations/{code}/cancel",code).contentType(MediaType.APPLICATION_JSON).content("{\"reason\":\"changed plan\"}")).andExpect(status().isOk()).andExpect(jsonPath("$.status").value("CANCELLED"));mvc.perform(post("/api/reservations/{code}/cancel",code).contentType(MediaType.APPLICATION_JSON).content("{}")).andExpect(status().isOk());}
 @Test void validationCapacityAndUnknownCodeAreSafe() throws Exception {mvc.perform(post("/api/reservations").contentType(MediaType.APPLICATION_JSON).content("{}")).andExpect(status().isBadRequest());mvc.perform(post("/api/reservations").contentType(MediaType.APPLICATION_JSON).content(body(plate(),"MOTORBIKE",80,20))).andExpect(status().isBadRequest());create(plate(),"CAR");mvc.perform(post("/api/reservations").contentType(MediaType.APPLICATION_JSON).content(body(plate(),"CAR",20,80))).andExpect(status().isConflict());mvc.perform(get("/api/reservations/unknown-code")).andExpect(status().isNotFound());}
 @Test void internalConsumeProtectsAndValidatesLifecycle() throws Exception {String code=create(plate(),"MOTORBIKE");String consume="{\"vehiclePlate\":\"59A1-99111\",\"vehicleType\":\"MOTORBIKE\",\"parkingSessionId\":\"session-1\",\"checkInRequestId\":\"request-1\"}";mvc.perform(post("/internal/reservations/{code}/consume",code).contentType(MediaType.APPLICATION_JSON).content(consume)).andExpect(status().isUnauthorized());mvc.perform(post("/internal/reservations/{code}/consume",code).header("X-Internal-Service-Token","wrong").contentType(MediaType.APPLICATION_JSON).content(consume)).andExpect(status().isUnauthorized());String matching=consume.replace("59A1-99111",lastPlate(code));mvc.perform(post("/internal/reservations/{code}/consume",code).header("X-Internal-Service-Token",internal()).contentType(MediaType.APPLICATION_JSON).content(matching)).andExpect(status().isOk()).andExpect(jsonPath("$.status").value("CONSUMED"));mvc.perform(post("/internal/reservations/{code}/consume",code).header("X-Internal-Service-Token",internal()).contentType(MediaType.APPLICATION_JSON).content(matching.replace("request-1","request-2"))).andExpect(status().isConflict());}
 @Test void consumeRejectsMismatchAndCancelledReservation() throws Exception {String code=create(plate(),"MOTORBIKE");mvc.perform(post("/internal/reservations/{code}/consume",code).header("X-Internal-Service-Token",internal()).contentType(MediaType.APPLICATION_JSON).content("{\"vehiclePlate\":\"30A-99999\",\"vehicleType\":\"MOTORBIKE\",\"parkingSessionId\":\"s\",\"checkInRequestId\":\"r\"}")).andExpect(status().isConflict());String cancel=create(plate(),"MOTORBIKE");mvc.perform(post("/api/reservations/{code}/cancel",cancel).contentType(MediaType.APPLICATION_JSON).content("{}")).andExpect(status().isOk());mvc.perform(post("/internal/reservations/{code}/consume",cancel).header("X-Internal-Service-Token",internal()).contentType(MediaType.APPLICATION_JSON).content("{\"vehiclePlate\":\"x\",\"vehicleType\":\"MOTORBIKE\",\"parkingSessionId\":\"s\",\"checkInRequestId\":\"r\"}")).andExpect(status().isConflict());}
 @Test void listAndExpireRequireStaffOrAdmin() throws Exception {mvc.perform(get("/api/reservations")).andExpect(status().isUnauthorized());mvc.perform(get("/api/reservations").header("Authorization","Bearer "+token("MERCHANT_STAFF"))).andExpect(status().isForbidden());mvc.perform(get("/api/reservations").header("Authorization","Bearer "+token("PARKING_STAFF"))).andExpect(status().isOk());mvc.perform(post("/api/reservations/expire").header("Authorization","Bearer "+token("MERCHANT_STAFF"))).andExpect(status().isForbidden());mvc.perform(post("/api/reservations/expire").header("Authorization","Bearer "+token("ADMIN"))).andExpect(status().isOk());}
 private String create(String plate,String type)throws Exception{var r=mvc.perform(post("/api/reservations").contentType(MediaType.APPLICATION_JSON).content(body(plate,type,20,80))).andExpect(status().isCreated()).andReturn();return json.readTree(r.getResponse().getContentAsString()).path("reservationCode").asText();} private String lastPlate(String code)throws Exception{var r=mvc.perform(get("/api/reservations/{code}",code)).andReturn();return json.readTree(r.getResponse().getContentAsString()).path("vehiclePlate").asText();} private String body(String plate,String type,int from,int until){return "{\"vehiclePlate\":\""+plate+"\",\"vehicleType\":\""+type+"\",\"reservedFrom\":\""+Instant.now().plusSeconds(from*60)+"\",\"reservedUntil\":\""+Instant.now().plusSeconds(until*60)+"\"}";} private String plate(){return "59A1-"+UUID.randomUUID().toString().substring(0,5).replace("-","1");} private String internal(){return "parkflow-local-internal-token-change-me";} private String token(String role){Instant n=Instant.now();return Jwts.builder().subject("test").claim("userId","id").claim("roles",List.of(role)).issuedAt(Date.from(n)).expiration(Date.from(n.plusSeconds(3600))).signWith(Keys.hmacShaKeyFor(SECRET.getBytes(StandardCharsets.UTF_8))).compact();}}
